esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE node_cert_expiration_seconds IS NOT NULL
| STATS min_expiry_s = MIN(node_cert_expiration_seconds) BY node, path, cluster
| EVAL days_until_expiry = ROUND(min_expiry_s / 86400, 1)
// Alert when any certificate expires within 30 days
// Expired certificates break intra-cluster communication and client TLS
// Adjust threshold: 30 days for early warning, 7 days is critical
// The 'path' dimension identifies which certificate file is expiring
| WHERE days_until_expiry < 30
| SORT days_until_expiry ASC
